import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases / processing fee ---
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // --- Base premiums for single main items ---
  it.todo("single plain sword (newcomer first item) → base 100 + first-insurance 10 + fee 5 = 115 G");
  it.todo("single plain amulet (newcomer first item) → base 60 + first 6 + fee 5 = 71 G");
  it.todo("single plain staff (newcomer first item) → base 80 + first 8 + fee 5 = 93 G");
  it.todo("single plain potion (newcomer first item) → base 40 + first 4 + fee 5 = 49 G");

  // --- Components and "building blocks of 3 alike" ---
  it.todo("2 runes → base 50 G (no block)");
  it.todo("3 runes → base 60 G (block applies)");
  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
  it.todo("7 runes → base 175 G (one block of 3 + 4 singles = 60 + 100)");
  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");

  // --- Item-specific modifiers (cursed, high enchantment) ---
  it.todo("cursed sword adds 50% surcharge on the cursed item's base premium");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("loyalty discount applies for customer with exactly 2 years");
  it.todo("loyalty discount does NOT apply for customer with 1 year");
  it.todo("first insurance surcharge applies per item in a quote");
  it.todo("follow-up contract discount (15%) applies to second quote in scenario");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → cursed surcharge applies only to cursed item (210 G before further modifiers and fee)");

  // --- Rounding ---
  it.todo("premium of 197.5 G rounds UP to 198 G (MHPCO's favor)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
  it.todo("long-standing customer (3yrs), 2nd quote, cursed sword (steel, ench 7) → premium 160 G; first-insurance still applies to each new sword");

  // --- Quote error cases ---
  it.todo("quote with unknown item type → CLI exits non-zero, writes to stderr, no results to stdout");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to a rune (insurance 250 G), damage 200 G → payout 100 G");

  // --- Claim: enchantment threshold ---
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Claim: dragon material ---
  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");

  // --- Claim: enchantment threshold vs dragon material ---
  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");
  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench clause applies, then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per damaged item)");

  // --- Claim: multiple items of same type ---
  it.todo("two swords insured; dragon attack damages both → each damage entry treated separately with own deductible");
  it.todo("claim has more entries of a type than policy covers → CLI exits non-zero (claim rejected)");

  // --- Claim: cap exhaustion ---
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; modifiers don't raise cap)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword insured; two successive claims of 1500 G → first 1400 G payout cap remaining 600; second 600 G payout cap remaining 0");

  // --- Claim: rounding ---
  it.todo("payout calculation 350.5 G rounds DOWN to 350 G");

  // --- Claim error cases ---
  it.todo("claim references item not in policy → CLI exits non-zero, stderr");
  it.todo("claim references item with unknown type → CLI exits non-zero, stderr");
  it.todo("claim has damage with amount: -200 → CLI exits non-zero, stderr");
});

