const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const BLOCK_OF_3_BASE_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
type QuoteResult = { premium: number };

const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_SURCHARGE_RATE;

const itemPremium = (item: Item): number =>
  withFirstInsurance(BASE_PREMIUM[item.type]);

const componentGroupPremium = (type: string, count: number): number => {
  if (count === 3) return withFirstInsurance(BLOCK_OF_3_BASE_PREMIUM);
  return count * withFirstInsurance(BASE_PREMIUM[type]);
};

const sumItemPremiums = (items: Item[]): number => {
  const componentCounts = new Map<string, number>();
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      total += itemPremium(item);
    }
  }
  for (const [type, count] of componentCounts) {
    total += componentGroupPremium(type, count);
  }
  return total;
};

const quoteStep = (step: Step): QuoteResult => ({
  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
});

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
  results: scenario.steps.map(quoteStep),
});

