content.content:
const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const BLOCK_OF_3_BASE_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
type QuoteResult = { premium: number };

const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_SURCHARGE_RATE;

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
  const highEnchSurcharge =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
      : 0;
  return withFirstInsurance(base) + curseSurcharge + highEnchSurcharge;
};

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentGroupPremium = (type: string, count: number): number =>
  count === 3
    ? withFirstInsurance(BLOCK_OF_3_BASE_PREMIUM)
    : count * itemPremium({ type });

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumComponentPremiums = (components: Item[]): number =>
  Array.from(countByType(components)).reduce(
    (sum, [type, count]) => sum + componentGroupPremium(type, count),
    0,
  );

const sumMainItemPremiums = (mainItems: Item[]): number =>
  mainItems.reduce((sum, item) => sum + itemPremium(item), 0);

const sumItemPremiums = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((item) => !isComponent(item));
  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
};

const quoteStep = (step: Step): QuoteResult => ({
  premium: Math.ceil(sumItemPremiums(step.items) + PROCESSING_FEE),
});

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
  results: scenario.steps.map(quoteStep),
});

