const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const BLOCK_OF_3_BASE_PREMIUM = 60;
const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: "quote"; items: Item[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };
type QuoteResult = { premium: number };

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const itemSurcharges = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
  const highEnchSurcharge =
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
      : 0;
  return curseSurcharge + highEnchSurcharge;
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const componentGroupBase = (type: string, count: number): number =>
  count === 3 ? BLOCK_OF_3_BASE_PREMIUM : count * BASE_PREMIUM[type];

const policyBase = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((item) => !isComponent(item));
  const mainBase = mainItems.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const componentBase = Array.from(countByType(components)).reduce(
    (sum, [type, count]) => sum + componentGroupBase(type, count),
    0,
  );
  return mainBase + componentBase;
};

const sumItemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurcharges(item), 0);

const loyaltyDiscount = (customer: Customer, base: number): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;

const quoteStep = (step: Step, customer: Customer): QuoteResult => {
  const base = policyBase(step.items);
  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
  const premium =
    base +
    firstInsurance -
    loyaltyDiscount(customer, base) +
    sumItemSurcharges(step.items) +
    PROCESSING_FEE;
  return { premium: Math.ceil(premium) };
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
  results: scenario.steps.map((step) => quoteStep(step, scenario.customer)),
});

import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases / processing fee ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums for single main items ---
  it("single plain sword (newcomer first item) → base 100 + first-insurance 10 + fee 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single plain amulet (newcomer first item) → base 60 + first 6 + fee 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single plain staff (newcomer first item) → base 80 + first 8 + fee 5 = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single plain potion (newcomer first item) → base 40 + first 4 + fee 5 = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Components and "building blocks of 3 alike" ---
  it("2 runes → base 50 G (no block); final premium with first-insurance+fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → base 60 G (block applies); premium 60 + first 6 + fee 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → base 100 G (no block); premium = 100 + 10 + 5 = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → base 175 G (no block; block requires exactly 3); premium = 175 + 17.5 + 5 = 197.5 → rounds up to 198", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone → base 75 G (no block: different types); premium = 75 + 7.5 + 5 = 87.5 → 88", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → base 120 G (two separate blocks); premium = 120 + 12 + 5 = 137", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
      ] }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // --- Item-specific modifiers (cursed, high enchantment) ---
  it("cursed sword (newcomer, steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword with ench exactly 5 → 30% high-enchantment surcharge; premium = 100+30+10+5 = 145", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 → no high-enchantment surcharge; premium = 115", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("cursed sword ench=5 → both surcharges apply; premium = 100+50+30+10+5 = 195", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });

  // --- Policy-wide modifiers ---
  it("loyalty discount (2yrs) applies; plain sword premium = 100-20+10+5 = 95", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it.todo("loyalty discount does NOT apply for customer with 1 year");
  it.todo("first insurance surcharge applies per item in a quote");
  it.todo("follow-up contract discount (15%) applies to second quote in scenario");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → cursed surcharge applies only to cursed item (210 G before further modifiers and fee)");

  // --- Rounding ---
  it.todo("premium of 197.5 G rounds UP to 198 G (MHPCO's favor)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
  it.todo("long-standing customer (3yrs), 2nd quote, cursed sword (steel, ench 7) → premium 160 G; first-insurance still applies to each new sword");

  // --- Quote error cases ---
  it.todo("quote with unknown item type → CLI exits non-zero, writes to stderr, no results to stdout");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to a rune (insurance 250 G), damage 200 G → payout 100 G");

  // --- Claim: enchantment threshold ---
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Claim: dragon material ---
  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");

  // --- Claim: enchantment threshold vs dragon material ---
  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");
  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench clause applies, then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per damaged item)");

  // --- Claim: multiple items of same type ---
  it.todo("two swords insured; dragon attack damages both → each damage entry treated separately with own deductible");
  it.todo("claim has more entries of a type than policy covers → CLI exits non-zero (claim rejected)");

  // --- Claim: cap exhaustion ---
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; modifiers don't raise cap)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword insured; two successive claims of 1500 G → first 1400 G payout cap remaining 600; second 600 G payout cap remaining 0");

  // --- Claim: rounding ---
  it.todo("payout calculation 350.5 G rounds DOWN to 350 G");

  // --- Claim error cases ---
  it.todo("claim references item not in policy → CLI exits non-zero, stderr");
  it.todo("claim references item with unknown type → CLI exits non-zero, stderr");
  it.todo("claim has damage with amount: -200 → CLI exits non-zero, stderr");
});

