const quoteStep = (step: Step, customer: Customer, isFollowUp: boolean): QuoteResult => {
  const base = policyBase(step.items);
  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
  const followUpDiscount = isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
  const premium =
    base +
    firstInsurance -
